let s: string = ""

for (let a: number = 0; a < 4; a++) {
  for (let e: number = 0; e < 3; e++) {
    if (e % 3 == 2) {
      s = "UN" + s
    } else if (e % 3 == 1) {
      s = "LA" + s
    } else {
      s = "ME" + s
    }
  }
  s = "\n" + s // quebra a linha?
}

console.log(s)
